syntax:
# Basic if
if condition:
    # runs if True

# if-else
if condition:
    # runs if True
else:
    # runs if False

# if-elif-else
if condition1:
    # runs if condition1 True
elif condition2:
    # runs if condition2 True
elif condition3:
    # can have many elif
else:
    # runs if ALL above False

# Ternary (one-line)
value = true_val if condition else false_val

# Nested
if outer_condition:
    if inner_condition:
        # both True

