subtopics.code:
# Example 1: Grade calculator
def get_grade(score):
    if score >= 90:
        return 'A (Excellent)'
    elif score >= 80:
        return 'B (Good)'
    elif score >= 70:
        return 'C (Average)'
    elif score >= 60:
        return 'D (Below Average)'
    else:
        return 'F (Fail)'

for s in [95, 83, 72, 65, 45]:
    print(f'{s}: {get_grade(s)}')

# Example 2: Multiple conditions with and/or
age = 25
income = 50000
credit_score = 750

if age >= 21 and income >= 30000 and credit_score >= 700:
    print('Loan approved!')
elif age >= 21 and income >= 30000:
    print('Loan approved with higher interest')
elif age >= 18:
    print('Need co-signer')
else:
    print('Not eligible')
